src/container.ts: import { Injectable } from './decorators';
       type Services = {
         [name: string]: Function | { new (...args: any[]): any };
       };

       /**
        * Dependency Injection Container
        */
       export class DIContainer {
         private services: Services = {};

         /**
          * Register a service with the given name
          */
         register<T>(name: string, service: Function | { new (...args: any[]): T }): void {
           this.services[name] = service;
         }

         /**
          * Get a service by its name
          */
         get<T>(name: string, ...args: any[]): T {
           const service = this.services[name];
           if (typeof service === 'function') {
             return service(...args);
           } else {
             return new service(...args);
           }
         }
       }

       /**
        * Decorator for defining services as singletons
        */
       export function Injectable<T>(target: any): void {
         target.singleton = true;
       }

       // Usage
       const container = new DIContainer();
       container.register('serviceA', Injectable(class {
         constructor() {
           console.log('Service A');
         }
       }));
       container.get('serviceA');
       container.get('serviceA');
